        for svc in services:
            print(f"  - {svc['name']} -> {svc.get('host', 'N/A')}:{svc.get('port', 'N/A')}")

        routes = self.list_routes()
        print(f"\nRoutes ({len(routes)}):")
        for route in routes:
            svc_info = route.get("service", {})
            print(f"  - {route.get('name', 'unnamed')} | paths={route.get('paths')} | "
                  f"methods={route.get('methods')} | service_id={svc_info.get('id', 'N/A')[:8]}...")

        upstreams = self.list_upstreams()
        print(f"\nUpstreams ({len(upstreams)}):")
        for upstream in upstreams:
            print(f"  - {upstream['name']} (algorithm: {upstream.get('algorithm', 'N/A')})")

        plugins = self.list_plugins()
        print(f"\nPlugins ({len(plugins)}):")
        for plugin in plugins:
            scope = "global"
            if plugin.get("service"):
                scope = f"service:{plugin['service'].get('id', 'N/A')[:8]}"
            elif plugin.get("route"):
                scope = f"route:{plugin['route'].get('id', 'N/A')[:8]}"
            print(f"  - {plugin['name']} ({scope}) enabled={plugin.get('enabled')}")

        print("=" * 60)


